    98→# ===========================================================================
    99→Describe "Invoke-MaxSizePolicy" {
   100→    BeforeEach {
   101→        $now = [datetime]::UtcNow
   102→
   103→        # 5 artifacts ordered newest → oldest (so oldest are candidates for deletion)
   104→        $script:artifacts = @(
   105→            New-TestArtifact -Name "newest" -SizeBytes 200MB -CreatedAt $now.AddDays(-1)  -WorkflowRunId "run-1"
   106→            New-TestArtifact -Name "newer"  -SizeBytes 150MB -CreatedAt $now.AddDays(-3)  -WorkflowRunId "run-2"
   107→            New-TestArtifact -Name "mid"    -SizeBytes 100MB -CreatedAt $now.AddDays(-7)  -WorkflowRunId "run-3"
   108→            New-TestArtifact -Name "older"  -SizeBytes  80MB -CreatedAt $now.AddDays(-14) -WorkflowRunId "run-4"
   109→            New-TestArtifact -Name "oldest" -SizeBytes  50MB -CreatedAt $now.AddDays(-21) -WorkflowRunId "run-5"
   110→        )
   111→        # Total = 580 MB
   112→    }
   113→
   114→    It "marks oldest artifacts for deletion until total size is within limit" {
   115→        # Limit = 400 MB → must delete 180 MB worth (oldest first: 50 MB + 80 MB = 130 MB still over,
   116→        # then 100 MB more = 230 MB deleted, total 350 MB ≤ 400 MB)
   117→        $result = Invoke-MaxSizePolicy -Artifacts $script:artifacts -MaxTotalSizeBytes (400MB)
   118→        $toDelete = $result | Where-Object { $_.MarkedForDeletion -eq $true }
   119→        $toDelete.Name | Should -Contain "oldest"
   120→        $toDelete.Name | Should -Contain "older"
   121→        $toDelete.Name | Should -Contain "mid"
   122→    }
   123→
   124→    It "does not mark artifacts for deletion when total size is within limit" {
   125→        $result = Invoke-MaxSizePolicy -Artifacts $script:artifacts -MaxTotalSizeBytes (1GB)
   126→        $toDelete = $result | Where-Object { $_.MarkedForDeletion -eq $true }
   127→        $toDelete | Should -BeNullOrEmpty
   128→    }
   129→
   130→    It "respects already-marked artifacts (does not double-count their size)" {
   131→        # Pre-mark the newest artifact as already being deleted (e.g. from age policy)
   132→        $script:artifacts[0].MarkedForDeletion = $true
   133→
   134→        # With 200 MB already marked, remaining = 380 MB which is under 400 MB limit
   135→        $result = Invoke-MaxSizePolicy -Artifacts $script:artifacts -MaxTotalSizeBytes (400MB)
   136→        $newlyMarked = $result | Where-Object { $_.MarkedForDeletion -eq $true -and $_.Name -ne "newest" }
   137→        $newlyMarked | Should -BeNullOrEmpty
   138→    }
   139→}
